-- ============================================================================
-- 0024_migrate_legacy_v11.sql — Batch 8: nạp LẠI dữ liệu lịch sử từ
-- "File nhap lieu xang dau_v11 (1).xlsx" (bản mới nhất, có chỉ số KM/công-tơ-mét).
-- File v11 mới bổ sung KM cho ~478 dòng (47 xe) — nhờ đó rpc_vehicle_last_km trả
-- đúng "KM cũ" để form Nhập bơm tự điền. Danh mục/tồn đầu/18 kỳ tịnh cũ KHÔNG đổi
-- so với 0016 (đã đối chiếu) nên tái dùng nguyên logic transform của 0016; chỉ
-- GHI ĐÈ SẠCH: xóa mọi bút toán/kỳ/tồn-đầu legacy cũ rồi nạp lại từ DATA_GOC mới.
-- Idempotent qua cờ app_config 'legacy_migrated_v11'. KHÔNG sửa migration cũ.
-- ============================================================================

-- Bảng nạp thô (đã tạo ở 0016; create-if-not-exists để an toàn khi chạy độc lập).
create table if not exists _legacy_data_goc (
  seq int generated always as identity primary key,
  loai text, ngay date, sophieu text, doituong text, tec_nguon text,
  loaigd text, loaidau text, solit numeric(14,3), kmcu numeric(14,1), kmmoi numeric(14,1),
  nhacungcap text, dongia numeric(14,2), ghichu text
);
alter table _legacy_data_goc enable row level security;
revoke all on _legacy_data_goc from anon, authenticated;

-- Làm mới toàn bộ dữ liệu thô từ v11 (giữ 3 số lẻ lít; KM 1 số lẻ).
truncate _legacy_data_goc restart identity;


do $$
declare
  v_sys uuid;
begin
  if exists (select 1 from app_config where key = 'legacy_migrated_v11') then
    raise notice 'Đã migrate legacy v11 trước đó — bỏ qua.'; return;
  end if;
  -- Người thực hiện migrate = Admin đầu tiên (để created_by không null).
  select id into v_sys from profiles where role = 'Admin' order by created_at limit 1;

  -- 0) Xóa sạch mọi dữ liệu legacy cũ (từ 0016) để nạp lại từ v11 (ghi đè sạch).
  delete from stock_period_alloc where period_id in (select id from stock_period where note like 'Migrate legacy%');
  delete from stock_period where note like 'Migrate legacy%';
  delete from tank_opening where note like 'Migrate legacy%';
  delete from ledger where legacy;

  -- 1) Sổ cái: mỗi dòng DATA_GOC → ledger (legacy, DaDuyet).
                      liters, km_old, km_new, supplier_id, unit_price, note, status, legacy,
                      created_by, submitted_at, reviewed_at)
  select
    case when d.loai = 'NHAP' then 'nhap' else 'bom' end,
    d.ngay,
    v.id,
    tt.id,
    tk.id,                         -- chỉ téc vật lý; nguồn khác (dầu phụ/bơm ngoài) → null
    ot.id,
    coalesce(d.solit, 0),
    d.kmcu, d.kmmoi,
    sup.id,
    d.dongia,
    nullif(concat_ws(' | ',
      'LEGACY#' || d.seq::text,
      nullif(d.sophieu,''),
      case when tk.id is null and d.tec_nguon is not null then 'Nguồn: ' || d.tec_nguon end,
      nullif(d.ghichu,'')), ''),
    'DaDuyet', true,
    v_sys, now(), now()
  from _legacy_data_goc d
  left join vehicles v        on normalize_text(v.plate) = normalize_text(d.doituong)
  left join tanks tk          on normalize_text(tk.name) = normalize_text(d.tec_nguon)
  left join oil_types ot      on normalize_text(ot.name) = normalize_text(d.loaidau)
  left join suppliers sup     on normalize_text(sup.name) = normalize_text(d.nhacungcap)
  left join transaction_types tt on tt.code = case
      when d.loaigd = 'Xuất nội bộ từ téc' then 'xuat_noi_bo'
      when d.loaigd = 'Bơm ngoài'          then 'bom_ngoai'
      when d.loaigd in ('Nhap dau','Nhập vào kho/téc') then 'nhap_kho'
      else null end;

  -- 2) Tồn đầu gốc 1/1/2026 (giá trị 'Tồn đầu còn sổ' của kỳ đầu mỗi téc; còn lại 0).
  select tk.id, x.op, date '2026-01-01', 'Migrate legacy (1/1/2026)', v_sys
  from (values ('Téc 1', 0::numeric), ('Téc 2', 104), ('Téc 3', 5779),
               ('Téc cát nghiền', 0)) as x(name, op)
  join tanks tk on normalize_text(tk.name) = normalize_text(x.name)
  on conflict (tank_id) do nothing;

  -- 3) Kỳ tịnh cũ (DaChot) từ TINH_TEC.
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG001', tk.id, 'tinh_tec', '2026-04-20', '2026-05-11',
      (371.0 - 371.0), 371.0, 371.0, 0.0, 13789.0, 'DaChot', 'Migrate legacy (kỳ cũ #1)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 1');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG002', tk.id, 'tinh_tec', '2026-03-01', '2026-04-09',
      (65.0 - 65.0), 65.0, 65.0, 0.0, 8680.0, 'DaChot', 'Migrate legacy (kỳ cũ #2)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 1');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG003', tk.id, 'tinh_tec', '2026-02-03', '2026-02-26',
      (350.0 - 350.0), 350.0, 350.0, 0.0, 10823.0, 'DaChot', 'Migrate legacy (kỳ cũ #3)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 1');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG004', tk.id, 'tinh_tec', '2026-01-01', '2026-01-13',
      (757.0 - 757.0), 757.0, 757.0, 0.0, 20617.0, 'DaChot', 'Migrate legacy (kỳ cũ #4)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 2');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG005', tk.id, 'tinh_tec', '2026-01-24', '2026-02-04',
      (356.0 - 356.0), 356.0, 356.0, 0.0, 22574.0, 'DaChot', 'Migrate legacy (kỳ cũ #5)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 2');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG006', tk.id, 'tinh_tec', '2026-02-05', '2026-02-26',
      (272.0 - 272.0), 272.0, 272.0, 0.0, 8473.0, 'DaChot', 'Migrate legacy (kỳ cũ #6)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 2');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG007', tk.id, 'tinh_tec', '2026-03-01', '2026-04-06',
      (1009.0 - 1009.0), 1009.0, 1009.0, 0.0, 28426.0, 'DaChot', 'Migrate legacy (kỳ cũ #7)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 2');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG008', tk.id, 'tinh_tec', '2026-04-11', '2026-04-30',
      (1299.0 - 1299.0), 1299.0, 1299.0, 0.0, 30401.0, 'DaChot', 'Migrate legacy (kỳ cũ #8)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 2');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG009', tk.id, 'tinh_tec', '2026-01-01', '2026-01-05',
      (384.0 - 384.0), 384.0, 384.0, 0.0, 5395.0, 'DaChot', 'Migrate legacy (kỳ cũ #9)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 3');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG010', tk.id, 'tinh_tec', '2026-01-06', '2026-01-24',
      (826.0 - 826.0), 826.0, 826.0, 0.0, 21509.0, 'DaChot', 'Migrate legacy (kỳ cũ #10)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 3');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG011', tk.id, 'tinh_tec', '2026-02-12', '2026-03-25',
      (1005.0 - 1005.0), 1005.0, 1005.0, 0.0, 29125.0, 'DaChot', 'Migrate legacy (kỳ cũ #11)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 3');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG012', tk.id, 'tinh_tec', '2026-03-30', '2026-04-16',
      (140.0 - 140.0), 140.0, 140.0, 0.0, 15710.0, 'DaChot', 'Migrate legacy (kỳ cũ #12)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 3');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG013', tk.id, 'tinh_tec', '2026-04-19', '2026-05-23',
      (938.0 - 938.0), 938.0, 938.0, 0.0, 29077.0, 'DaChot', 'Migrate legacy (kỳ cũ #13)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 3');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG014', tk.id, 'tinh_tec', '2026-05-20', '2026-05-26',
      (379.0 - 379.0), 379.0, 379.0, 0.0, 7755.0, 'DaChot', 'Migrate legacy (kỳ cũ #14)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 1');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG015', tk.id, 'tinh_tec', '2026-05-18', '2026-06-11',
      (1630.0 - 1630.0), 1630.0, 1630.0, 0.0, 34366.0, 'DaChot', 'Migrate legacy (kỳ cũ #15)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 2');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG016', tk.id, 'tinh_tec', '2026-06-05', '2026-06-15',
      (368.0 - 368.0), 368.0, 368.0, 0.0, 8377.0, 'DaChot', 'Migrate legacy (kỳ cũ #16)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 1');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG017', tk.id, 'tinh_tec', '2026-06-05', '2026-06-26',
      (1428.0 - 1428.0), 1428.0, 1428.0, 0.0, 27987.0, 'DaChot', 'Migrate legacy (kỳ cũ #17)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 3');
      book_liters, tinh_am, tinh_duong, total_liters, status, note, created_by, closed_by, closed_at)
    select 'TINH-2026-LEG018', tk.id, 'tinh_tec', '2026-06-23', '2026-07-04',
      (1262.0 - 1262.0), 1262.0, 1262.0, 0.0, 21668.0, 'DaChot', 'Migrate legacy (kỳ cũ #18)', v_sys, v_sys, now()
    from tanks tk where normalize_text(tk.name) = normalize_text('Téc 2');

  -- 4) Phân bổ tịnh cho xe cho từng kỳ cũ (theo lít-trong-kỳ; dồn dư vào xe lít lớn nhất).
  declare
    v_p record; v_v record; v_total numeric; v_sum numeric; v_max uuid; v_a numeric;
  begin
    for v_p in select id, tank_id, start_date, close_date, tinh_am from stock_period
               where note like 'Migrate legacy (kỳ cũ%' and tinh_am > 0 loop
      select coalesce(sum(l.liters),0) into v_total from ledger l
        join transaction_types tt on tt.id = l.txn_type_id
        where l.tank_id = v_p.tank_id and l.entry_type='bom' and tt.kind='xuat'
          and l.vehicle_id is not null and l.legacy
          and l.entry_date between v_p.start_date and v_p.close_date;
      if v_total <= 0 then continue; end if;
      v_sum := 0; v_max := null;
      for v_v in select l.vehicle_id, sum(l.liters) lit from ledger l
          join transaction_types tt on tt.id = l.txn_type_id
          where l.tank_id = v_p.tank_id and l.entry_type='bom' and tt.kind='xuat'
            and l.vehicle_id is not null and l.legacy
            and l.entry_date between v_p.start_date and v_p.close_date
          group by l.vehicle_id order by sum(l.liters) desc loop
        if v_max is null then v_max := v_v.vehicle_id; end if;
        v_a := round(v_p.tinh_am * v_v.lit / v_total, 2);
          values (v_p.id, v_v.vehicle_id, v_v.lit, v_a, 0)
          on conflict (period_id, vehicle_id) do nothing;
        v_sum := v_sum + v_a;
      end loop;
      if v_max is not null and v_sum <> v_p.tinh_am then
        update stock_period_alloc set tinh_am = tinh_am + (v_p.tinh_am - v_sum)
          where period_id = v_p.id and vehicle_id = v_max;
      end if;
    end loop;
  end;

    on conflict (key) do nothing;
  raise notice 'Migrate legacy XONG: % dòng sổ cái, % kỳ tịnh.',
    (select count(*) from ledger where legacy), (select count(*) from stock_period where status='DaChot');
end $$;
